import{_ as e,o as a,c as o,a0 as s}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"Taxonomia Canônica do NEXUS — T Tiers e L Levels","description":"","frontmatter":{},"headers":[],"relativePath":"10_Fundacao/taxonomy.md","filePath":"10_Fundacao/taxonomy.md","lastUpdated":1782592277000}'),d={name:"10_Fundacao/taxonomy.md"};function n(r,t,i,l,c,p){return a(),o("div",null,[...t[0]||(t[0]=[s(`<h1 id="taxonomia-canonica-do-nexus-—-t-tiers-e-l-levels" tabindex="-1">Taxonomia Canônica do NEXUS — T Tiers e L Levels <a class="header-anchor" href="#taxonomia-canonica-do-nexus-—-t-tiers-e-l-levels" aria-label="Permalink to &quot;Taxonomia Canônica do NEXUS — T Tiers e L Levels&quot;">​</a></h1><blockquote><p>Gerado em 2026-06-21 · Atualizado em 2026-06-22. Reconcilia ADR-0010 (abstraction levels), ADR-0011 (tiers), e o estado real do código. Substitui interpretações conflitantes.</p></blockquote><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><ul><li><strong>T</strong> = tier tecnológico (T1 filesystem → T4 grafo → T5 algébrico/especulativo)</li><li><strong>L</strong> = nível de abstração cognitiva (L0 raw → L6 modelo mental)</li><li>O <code>level</code> no <strong>grafo T4</strong> (4=file, 2=semantic, 1=AST, 0=raw) é <strong>outra coisa</strong> — é posição na hierarquia do grafo, não abstração cognitiva. São conceitos ortogonais.</li></ul><hr><h2 id="_1-t-tiers-—-pilhas-tecnologicas" tabindex="-1">1. T Tiers — Pilhas Tecnológicas <a class="header-anchor" href="#_1-t-tiers-—-pilhas-tecnologicas" aria-label="Permalink to &quot;1. T Tiers — Pilhas Tecnológicas&quot;">​</a></h2><p>Definidos informalmente no ADR-0011. Cada tier é uma camada do sistema com natureza matemática distinta.</p><table tabindex="0"><thead><tr><th>Tier</th><th>Tecnologia</th><th>Natureza Matemática</th><th>Propósito</th><th>Status</th></tr></thead><tbody><tr><td><strong>T1</strong></td><td>Filesystem</td><td>Conjunto ordenado</td><td>Origem dos arquivos no disco</td><td>✅ Operacional</td></tr><tr><td><strong>T2</strong></td><td>PostgreSQL</td><td>Espaço relacional</td><td>Blobs, abstractions, metadados</td><td>✅ Operacional</td></tr><tr><td><strong>T3</strong></td><td>Qdrant</td><td>Espaço métrico</td><td>Busca semântica por similaridade vetorial</td><td>✅ Operacional</td></tr><tr><td><strong>T4</strong></td><td>Grafo (agent_links)</td><td>Topologia discreta</td><td>Navegação multi-relacional (part_of, depends_on, bridge, contradicts)</td><td>✅ Operacional</td></tr><tr><td><strong>T5</strong></td><td>— (especulativo)</td><td>Álgebra / Teoria de Grupos</td><td>Invariantes estruturais, isomorfismos, formas canônicas</td><td>❌ Pesquisa (ADR-0011)</td></tr></tbody></table><h3 id="dependencias-entre-tiers" tabindex="-1">Dependências entre Tiers <a class="header-anchor" href="#dependencias-entre-tiers" aria-label="Permalink to &quot;Dependências entre Tiers&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T1 (arquivos)</span></span>
<span class="line"><span> └→ T2 (blobs + abstractions)</span></span>
<span class="line"><span>     ├→ T3 (embeddings → Qdrant)</span></span>
<span class="line"><span>     └→ T4 (arestas → agent_links)</span></span>
<span class="line"><span>         └→ T5 (estruturas algébricas — futuro)</span></span></code></pre></div><hr><h2 id="_2-l-levels-—-abstraction-levels" tabindex="-1">2. L Levels — Abstraction Levels <a class="header-anchor" href="#_2-l-levels-—-abstraction-levels" aria-label="Permalink to &quot;2. L Levels — Abstraction Levels&quot;">​</a></h2><p>Definidos no ADR-0010. Cada level responde uma pergunta que o anterior não consegue responder sozinho. O contexto de entrada de cada level é a saída do level anterior.</p><h3 id="tabela-canonica" tabindex="-1">Tabela Canônica <a class="header-anchor" href="#tabela-canonica" aria-label="Permalink to &quot;Tabela Canônica&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Level</th><th>Pergunta</th><th>Granularidade</th><th>Entrada</th><th>Modelo</th><th>Estado</th></tr></thead><tbody><tr><td><strong>L0</strong></td><td>O que está escrito?</td><td>chunk (~2000 chars)</td><td>Arquivo cru</td><td>— (verbatim)</td><td>✅ 15.499 chunks</td></tr><tr><td><strong>L1</strong></td><td>O que existe?</td><td>blob (arquivo)</td><td>Chunks L0</td><td>ast-grep</td><td>⚠️ 490/796 blobs (travado)</td></tr><tr><td><strong>L2</strong></td><td>O que faz?</td><td>chunk → semântica</td><td>Chunks L0 + L1</td><td>qwen2.5-coder:nexus</td><td>✅ 14.920 abs (96%)</td></tr><tr><td><strong>L3</strong></td><td>O que significa?</td><td>blob → propósito do módulo</td><td>L2s do mesmo blob</td><td>qwen2.5-coder:nexus</td><td>⚠️ endpoint ok, nunca disparado</td></tr><tr><td><strong>L4</strong></td><td>O que emerge?</td><td>cluster de blobs → padrões</td><td>L3s do cluster</td><td>—</td><td>❌ Não implementado</td></tr><tr><td><strong>L5</strong></td><td>O que pode estar errado?</td><td>sistema → hipóteses falseáveis</td><td>L4s + contradições T4</td><td>—</td><td>❌ Não implementado</td></tr><tr><td><strong>L6</strong></td><td>O que o sistema quer ser?</td><td>projeto → modelo mental</td><td>Todos os Ls inferiores</td><td>—</td><td>❌ Não implementado</td></tr></tbody></table><h3 id="regra-fundamental" tabindex="-1">Regra Fundamental <a class="header-anchor" href="#regra-fundamental" aria-label="Permalink to &quot;Regra Fundamental&quot;">​</a></h3><blockquote><p>A abstração só pode ser tão boa quanto o contexto que ela recebe.</p></blockquote><p>L2 alimentado por um chunk individual (200 chars) produz ruído (problema atual do L2 com modelo pequeno). L3 alimentado por um blob inteiro (todos os L2s) produz síntese útil. L4 alimentado por um cluster produz padrões emergentes.</p><hr><h2 id="_3-niveis-no-grafo-t4-nao-confundir-com-l-levels" tabindex="-1">3. Níveis no Grafo T4 (NÃO CONFUNDIR com L Levels) <a class="header-anchor" href="#_3-niveis-no-grafo-t4-nao-confundir-com-l-levels" aria-label="Permalink to &quot;3. Níveis no Grafo T4 (NÃO CONFUNDIR com L Levels)&quot;">​</a></h2><p>O grafo T4 armazena nós com um campo <code>level</code> que indica a <strong>posição na hierarquia do grafo</strong>. Isso é um conceito <strong>estrutural</strong>, não cognitivo.</p><table tabindex="0"><thead><tr><th>Level T4</th><th>Kind</th><th>Representa</th><th>Quantidade</th></tr></thead><tbody><tr><td>4</td><td><code>file</code></td><td>Arquivo físico no disco</td><td>796 nós</td></tr><tr><td>2</td><td>—</td><td>Chunk semântico (L2 summary)</td><td>14.920 nós</td></tr><tr><td>1</td><td>—</td><td>Chunk estrutural (AST)</td><td>490 nós</td></tr><tr><td>0</td><td>—</td><td>Chunk raw (código fonte)</td><td>15.499 nós</td></tr></tbody></table><p><strong>Confusão comum:</strong> O level 4 no T4 é um <em>file node</em>, mas NÃO é o mesmo que L4 (abstração cognitiva de clusters). Um file node (T4 level 4) está no nível de abstração <strong>L1/L2</strong> — é um arquivo concreto, não um padrão emergente.</p><p>O mapeamento correto é:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>L0 (raw text)     → T4 level 0 chunks</span></span>
<span class="line"><span>L1 (AST)          → T4 level 1 chunks + T4 level 4 files</span></span>
<span class="line"><span>L2 (semântica)    → T4 level 2 chunks</span></span>
<span class="line"><span>L3 (propósito)    → module_synthesis (tabela separada, não no T4)</span></span>
<span class="line"><span>L4+ (emergência)  → Fora do T4 (reflections ou tabela própria)</span></span></code></pre></div><hr><h2 id="_4-estado-atual-da-implementacao" tabindex="-1">4. Estado Atual da Implementação <a class="header-anchor" href="#_4-estado-atual-da-implementacao" aria-label="Permalink to &quot;4. Estado Atual da Implementação&quot;">​</a></h2><h3 id="o-que-funciona" tabindex="-1">O que funciona <a class="header-anchor" href="#o-que-funciona" aria-label="Permalink to &quot;O que funciona&quot;">​</a></h3><ul><li>L0, L2: completos (L0: 100% blobs chunkados, L2: 14.920 abs — 96%)</li><li>T1-T4: operacionais (engine, postgres, qdrant, agent_links)</li><li>Operadores T4: project, abstract, compile (REST). find e expand <strong>não implementados</strong> (404). chain aceita <code>steps</code>.</li></ul><h3 id="o-que-esta-incompleto-nos-6-l" tabindex="-1">O que está incompleto nos 6 L <a class="header-anchor" href="#o-que-esta-incompleto-nos-6-l" aria-label="Permalink to &quot;O que está incompleto nos 6 L&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Problema</th><th>Solução</th></tr></thead><tbody><tr><td>L1 travado em 490/796</td><td>Pipeline serializa L1→L2; L2 (LLM) domina o ciclo</td><td>Separar ciclos: L1 roda todo ciclo, L2 a cada 3 ciclos</td></tr><tr><td>L3 nunca disparado</td><td><code>POST /l3-synthesize</code> existe mas não é chamado</td><td>Auto-disparar após cada ciclo de L2</td></tr><tr><td>L4 não implementado</td><td>Síntese cross-blob inexistente</td><td>Implementar clusterização por módulo + LLM</td></tr><tr><td>L5 não implementado</td><td>Hipóteses falseáveis a partir de contradições</td><td>Usar <code>contradicts</code> do T4 como seed</td></tr><tr><td>L6 não implementado</td><td>Modelo mental do sistema</td><td>Síntese final de todos os Ls</td></tr></tbody></table><h3 id="o-que-esta-incompleto-nos-t" tabindex="-1">O que está incompleto nos T <a class="header-anchor" href="#o-que-esta-incompleto-nos-t" aria-label="Permalink to &quot;O que está incompleto nos T&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Problema</th><th>Solução</th></tr></thead><tbody><tr><td>T5 não iniciado</td><td>Especulativo (ADR-0011)</td><td>Pesquisar quando L4-L6 estiverem estáveis</td></tr></tbody></table><hr><h2 id="_5-proximos-passos" tabindex="-1">5. Próximos Passos <a class="header-anchor" href="#_5-proximos-passos" aria-label="Permalink to &quot;5. Próximos Passos&quot;">​</a></h2><p>Prioridade (1 = agora, 5 = futuro):</p><ol><li><strong>Destravar L1</strong> — separar frequência L1/L2 no enrichment pipeline (Rust)</li><li><strong>Ativar L3</strong> — auto-disparar <code>POST /l3-synthesize</code></li><li><strong>Melhorar L2</strong> — contexto maior (~2000 chars em vez de ~200)</li><li><strong>Implementar L4</strong> — clusterização cross-blob</li><li><strong>Implementar L5/L6</strong> — hipóteses + modelo mental</li><li><strong>T5</strong> — pesquisa algébrica (quando L4-L6 estiverem maduros)</li></ol><hr><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>ADR-0002: Operadores Relacionais Composáveis no T4</li><li>ADR-0010: Hierarquia de Levels de Abstração e o Papel do Tempo</li><li>ADR-0011: T5 — Espaço Algébrico e Analogias com Teoria de Grupos</li><li>ADR-0022: Auditoria de Implementação — Estado Atual vs ADRs</li><li><code>docs/features/injection-point-map.md</code>: Pontos de injeção por feature</li><li><code>docs_archive_backup/legacy_pre_federation/T4_GRAPH_NORMS.md</code>: Normas do grafo T4</li></ul>`,40)])])}const h=e(d,[["render",n]]);export{m as __pageData,h as default};
